Code.Terraform:
```hcl
resource "aws_cloudfront_distribution" "<example_resource_name>" {
  enabled = true

  origin {
    domain_name = "<example_origin_domain>"
    origin_id   = "origin1"
    s3_origin_config {}
  }

  default_cache_behavior {
    target_origin_id       = "origin1"
    viewer_protocol_policy = "redirect-to-https"
    forwarded_values { query_string = false }
  }

  aliases = ["<example_domain>"]  # 关键：添加证书覆盖的 CNAME

  viewer_certificate {
    acm_certificate_arn = "<example_certificate_arn>"  # 关键：自定义 ACM 证书（在 us-east-1 中）
    ssl_support_method  = "sni-only"                    # 关键：使用 ACM 证书时必需
  }
}
```
